module sr_latch (  
    input wire SRLatch_S,  
    input wire R,  
    output reg Q  
);  
    always @ (SRLatch_S, R) begin  
        if (SRLatch_S && ~R)  
            Q <= 1; // Set  
        else if (~SRLatch_S && R)  
            Q <= 0; // Reset  
        // If both SRLatch_S and R are low, retain the state (no change)  
        // If both SRLatch_S and R are high, maintain the previous state (indeterminate)  
    end  
endmodule
